// Use n8n static data to remember previously processed Conversation IDs
const staticData = $getWorkflowStaticData('global');
staticData.processedIds = staticData.processedIds || [];

const newItems = [];
for (const item of $input.all()) {
    const msgId = item.json.conversationId || item.json.id;
    if (!staticData.processedIds.includes(msgId)) {
        newItems.push(item);
        staticData.processedIds.push(msgId);
    }
}

// .slice(-100) is safer than splice() against n8n's static data proxy object
staticData.processedIds = staticData.processedIds.slice(-100);

return newItems;

// Strip markdown code fences before parsing — OpenAI wraps JSON in ```json blocks even when asked not to
let aiResponse = {};
try {
    let rawContent = $input.first().json.message.content;
    let cleanContent = rawContent.replace(/```json/g, '').replace(/```/g, '').trim();
    aiResponse = JSON.parse(cleanContent);
} catch (e) {
    aiResponse = { Strategic_Decisions: [], Action_Items: [] };
}

const decisions = aiResponse.Strategic_Decisions || [];
const actions = aiResponse.Action_Items || [];

const decisionItems = decisions.map(d => ({ json: d }));
const actionItems = actions.map(a => ({ json: a }));

// Output 0 -> SharePoint (Decisions) | Output 1 -> Normalize Due Date -> To Do (Actions)
// IMPORTANT: Set Outputs to 2 in this node's Settings tab on the canvas
return [decisionItems, actionItems];

// The LLM is forced to output YYYY-MM-DD or null — no freeform strings.
// Converts that to the dateTimeTimeZone object Microsoft Graph requires.
// Microsoft To Do rejects plain ISO strings; it needs { dateTime, timeZone }.
//
// Deadline = 14:00 UTC = 17:00 EEST (UTC+3, Finland summer time).
// Adjust the hour constant below if your team operates in a different timezone.

const DEADLINE_HOUR_UTC = 14;
const items = $input.all();

return items.map(item => {
    const raw = item.json.due_date;
    let dueDateTimeZone = null;

    if (raw && raw !== 'null' && raw.trim() !== '') {
        // Only accept strings the LLM formatted correctly as YYYY-MM-DD
        const isValidFormat = /^\d{4}-\d{2}-\d{2}$/.test(raw.trim());
        if (isValidFormat) {
            // Build the dateTimeTimeZone object Microsoft Graph / To Do requires
            dueDateTimeZone = {
                dateTime: `${raw.trim()}T${String(DEADLINE_HOUR_UTC).padStart(2, '0')}:00:00`,
                timeZone: 'UTC'
            };
        }
    }

    return {
        json: {
            ...item.json,
            due_date_graph: dueDateTimeZone
        }
    };
});
